import * as React from "react";

import { cn } from "@/lib/utils";

import "./squeeze-animation.css";

type SqueezeAnimationValue = number | string;

export type SqueezeOptions = {
  /** Horizontal rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeX?: SqueezeAnimationValue;
  /** Vertical rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeY?: SqueezeAnimationValue;
  /** Animation duration. Numeric values are converted to ms. */
  duration?: SqueezeAnimationValue;
};

export type SqueezeProps = React.ComponentPropsWithoutRef<"span"> &
  SqueezeOptions & {
    /** Classes applied to the animated child wrapper. */
    targetClassName?: string;
  };

export function Squeeze({
  className,
  children,
  duration,
  shakeX,
  shakeY,
  style,
  targetClassName,
  ...props
}: SqueezeProps) {
  return (
    <span
      data-slot="squeeze"
      className={cn("squeeze-animation inline-flex", className)}
      style={getSqueezeAnimationStyle({ duration, shakeX, shakeY }, style)}
      {...props}
    >
      <span
        data-slot="squeeze-target"
        className={cn("squeeze-animation-target inline-flex", targetClassName)}
      >
        {children}
      </span>
    </span>
  );
}

export type SqueezeAnimationProps = React.ComponentPropsWithoutRef<"div"> &
  SqueezeOptions & {
    /** Classes applied to the animated SVG group. */
    targetClassName?: string;
  };

export function SqueezeAnimation({
  className,
  duration,
  shakeX,
  shakeY,
  style,
  targetClassName,
  ...props
}: SqueezeAnimationProps) {
  return (
    <div
      data-slot="squeeze-animation"
      className={cn(
        "squeeze-animation flex flex-col items-center text-foreground",
        className,
      )}
      style={getSqueezeAnimationStyle({ duration, shakeX, shakeY }, style)}
      {...props}
    >
      <svg
        viewBox="0 0 100 100"
        aria-hidden="true"
        className="squeeze-animation-svg h-auto w-full max-w-80"
      >
        <g
          data-slot="squeeze-animation-target"
          className={cn(
            "squeeze-animation-target squeeze-animation-icon",
            targetClassName,
          )}
        >
          <rect
            x="26"
            y="30"
            width="48"
            height="40"
            rx="12"
            fill="currentColor"
            fillOpacity="0.1"
            stroke="currentColor"
            strokeWidth="6"
          />
          <path
            d="M 38 46 H 62"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
          <path
            d="M 38 58 H 54"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
        </g>
      </svg>
    </div>
  );
}

function getSqueezeAnimationStyle(
  {
    duration,
    shakeX,
    shakeY,
  }: Pick<SqueezeOptions, "duration" | "shakeX" | "shakeY">,
  style: React.CSSProperties | undefined,
) {
  if (duration === undefined && shakeX === undefined && shakeY === undefined) {
    return style;
  }

  return {
    ...style,
    ...(duration !== undefined
      ? { "--squeeze-animation-duration": formatDurationValue(duration) }
      : {}),
    ...(shakeX !== undefined
      ? { "--squeeze-animation-shake-x": formatShakeValue(shakeX) }
      : {}),
    ...(shakeY !== undefined
      ? { "--squeeze-animation-shake-y": formatShakeValue(shakeY) }
      : {}),
  } as React.CSSProperties;
}

function formatShakeValue(value: SqueezeAnimationValue | undefined) {
  return typeof value === "number" ? `${value}px` : value;
}

function formatDurationValue(value: SqueezeAnimationValue | undefined) {
  return typeof value === "number" ? `${value}ms` : value;
}

.squeeze-animation {
  --squeeze-animation-duration: 1240ms;
  --squeeze-animation-shake-x: 5px;
  --squeeze-animation-shake-y: 3px;
}

.squeeze-animation-target,
.squeeze-animation-icon {
  backface-visibility: hidden;
  transform-origin: center;
  animation: squeeze-animation var(--squeeze-animation-duration) both;
  will-change: transform;
}

.squeeze-animation-svg .squeeze-animation-target,
.squeeze-animation-icon {
  transform-box: fill-box;
}

@keyframes squeeze-animation {
  0% {
    transform: translate(0, 0) scale(1);
    animation-timing-function: cubic-bezier(0.19, 1, 0.22, 1);
  }
  10% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.18),
        calc(var(--squeeze-animation-shake-y) * 0.22)
      )
      scale(1.22, 0.78);
    animation-timing-function: cubic-bezier(0.65, 0, 0.35, 1);
  }
  18% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.4),
        calc(var(--squeeze-animation-shake-y) * 0.5)
      )
      scale(1.42, 0.6);
    animation-timing-function: cubic-bezier(0.34, 1.35, 0.64, 1);
  }
  23% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.3),
        calc(var(--squeeze-animation-shake-y) * 0.34)
      )
      scale(1.32, 0.7);
    animation-timing-function: cubic-bezier(0.65, 0, 0.35, 1);
  }
  28%,
  38% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.35),
        calc(var(--squeeze-animation-shake-y) * 0.42)
      )
      scale(1.38, 0.64);
    animation-timing-function: cubic-bezier(0.19, 1, 0.22, 1);
  }
  47% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 1.25),
        calc(var(--squeeze-animation-shake-y) * -1.25)
      )
      scale(0.72, 1.32);
    animation-timing-function: cubic-bezier(0.34, 1.56, 0.64, 1);
  }
  58% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.85),
        calc(var(--squeeze-animation-shake-y) * 0.72)
      )
      scale(1.2, 0.82);
    animation-timing-function: cubic-bezier(0.34, 1.4, 0.64, 1);
  }
  74% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.48),
        calc(var(--squeeze-animation-shake-y) * -0.44)
      )
      scale(0.91, 1.1);
    animation-timing-function: cubic-bezier(0.34, 1.28, 0.64, 1);
  }
  90% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.18),
        calc(var(--squeeze-animation-shake-y) * 0.18)
      )
      scale(1.05, 0.965);
    animation-timing-function: cubic-bezier(0.34, 1.12, 0.64, 1);
  }
  100% {
    transform: translate(0, 0) scale(1);
  }
}

@media (prefers-reduced-motion: reduce) {
  .squeeze-animation-target,
  .squeeze-animation-icon {
    animation: none;
    will-change: auto;
  }
}
